# Build sidebar service link
function MkSl([string]$href, [string]$svg, [string]$label) {
    return "<a href=""$href"" class=""sidebar-link"">$svg$label</a>"
}
# Build related card
function MkRc([string]$href, [string]$label, [string]$title, [string]$desc) {
    return "<a href=""$href"" class=""related-card reveal""><span class=""related-card-label"">$label</span><h4>$title</h4><p>$desc</p><span class=""related-card-arrow"" data-i18n=""proj.detail.view"">View Project &rarr;</span></a>"
}

# Build full project page
function MkPage {
    param([string]$f,[string]$pn,[string]$pt,[string]$md,[string]$hlEN,[string]$hlPT,[string]$bc,
          [string]$yr,[string]$prov,[string]$cl,[string]$fund,[string]$sec,[string]$svd,[string]$tgs,
          [string]$oEN,[string]$oPT,[string]$scEN,[string]$scPT,[string]$evEN,[string]$evPT,
          [string]$rEN,[string]$rPT,[string]$svl,[string]$rel)

    $h = "<!DOCTYPE html>`n<html lang=""en""><head>`n<meta charset=""UTF-8"" />`n<meta name=""viewport"" content=""width=device-width, initial-scale=1.0"" />`n<meta name=""description"" content=""$md"" />`n<title>$pt | Enviestudos Projects</title>`n<link rel=""preconnect"" href=""https://fonts.googleapis.com"" /><link rel=""preconnect"" href=""https://fonts.gstatic.com"" crossorigin />`n<link href=""https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;600;700;800&amp;family=Inter:wght@300;400;500;600&amp;display=swap"" rel=""stylesheet"" />`n<link rel=""stylesheet"" href=""css/style.css"" />`n</head><body>`n$nav`n<header class=""page-hero""><div class=""container""><div class=""page-hero-content""><div class=""page-hero-label""><span class=""lang-en"">$hlEN</span><span class=""lang-pt"">$hlPT</span></div><h1 data-i18n=""proj.p$pn.title""></h1><div class=""proj-hero-meta""><div class=""proj-hero-meta-item""><span class=""proj-hero-meta-label"" data-i18n=""proj.detail.year"">Year</span><span class=""proj-hero-meta-value"">$yr</span></div><div class=""proj-hero-meta-item""><span class=""proj-hero-meta-label"" data-i18n=""proj.detail.province"">Province</span><span class=""proj-hero-meta-value"">$prov</span></div><div class=""proj-hero-meta-item""><span class=""proj-hero-meta-label"" data-i18n=""proj.detail.client"">Client</span><span class=""proj-hero-meta-value"">$cl</span></div><div class=""proj-hero-meta-item""><span class=""proj-hero-meta-label"" data-i18n=""proj.detail.funder"">Funder</span><span class=""proj-hero-meta-value"">$fund</span></div></div><nav class=""breadcrumb"" aria-label=""Breadcrumb"" style=""margin-top:1.5rem;""><a href=""index.html"" data-i18n=""bc.home"">Home</a><span>&rsaquo;</span><a href=""projects.html"" data-i18n=""nav.projects"">Projects</a><span>&rsaquo;</span><span>$bc</span></nav></div></div></header>`n<section class=""section-pad"" style=""background:var(--clr-white);""><div class=""container""><div class=""detail-layout""><div class=""detail-body reveal""><h2 data-i18n=""proj.detail.overview"">Project Overview</h2><div class=""lang-en"">$oEN</div><div class=""lang-pt"">$oPT</div><h2 data-i18n=""proj.detail.scope"">Scope of Work</h2><div class=""lang-en""><ul>$scEN</ul></div><div class=""lang-pt""><ul>$scPT</ul></div><h2 data-i18n=""proj.detail.enviro"">Environmental Considerations</h2><div class=""lang-en""><ul>$evEN</ul></div><div class=""lang-pt""><ul>$evPT</ul></div><h2 data-i18n=""proj.detail.results"">Results &amp; Impact</h2><div class=""lang-en""><p>$rEN</p></div><div class=""lang-pt""><p>$rPT</p></div><div class=""tags-row"" style=""margin-top:1.5rem;"">$tgs</div></div><aside class=""detail-sidebar reveal reveal-delay-2""><div class=""sidebar-card""><div class=""sidebar-card-title"" data-i18n=""proj.detail.details"">Project Details</div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.sector"">Sector</span><span class=""sidebar-row-value"">$sec</span></div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.year"">Year</span><span class=""sidebar-row-value"">$yr</span></div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.province"">Province</span><span class=""sidebar-row-value"">$prov</span></div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.client"">Client</span><span class=""sidebar-row-value"">$cl</span></div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.funder"">Funder</span><span class=""sidebar-row-value"">$fund</span></div><div class=""sidebar-row""><span class=""sidebar-row-label"" data-i18n=""proj.detail.svc-del"">Services Delivered</span><span class=""sidebar-row-value"">$svd</span></div></div><div class=""sidebar-card""><div class=""sidebar-card-title"" data-i18n=""proj.detail.svc-links"">Related Services</div><div class=""sidebar-links"">$svl</div></div></aside></div></div></section>`n<section class=""section-pad"" style=""background:var(--clr-light-bg);""><div class=""container""><div class=""text-center reveal""><div class=""section-label"" data-i18n=""proj.detail.more"">More Projects</div><h2 class=""section-title"" data-i18n=""proj.detail.related"">Related Case Studies</h2></div><div class=""related-grid"" style=""margin-top:2rem;"">$rel</div></div></section>`n<section class=""cta-section section-pad""><div class=""container""><div class=""cta-inner reveal""><div class=""section-label"" data-i18n=""proj.cta.label"">Let's Work Together</div><h2 data-i18n=""proj.cta.title"">Ready to Add Your Project to Our Portfolio?</h2><p data-i18n=""proj.cta.desc"">Contact us today to discuss your project's environmental requirements.</p><div class=""cta-actions""><a href=""contact.html"" class=""btn btn-primary"" data-i18n=""proj.cta.btn1"">Start a Conversation</a><a href=""projects.html"" class=""btn btn-outline"" data-i18n=""proj.detail.all"">All Projects</a></div></div></div></section>`n$foot`n</body></html>"
    [System.IO.File]::WriteAllText("$dir\$f", $h, (New-Object System.Text.UTF8Encoding($false)))
    Write-Host "OK: $f"
}

# ─── Project 4: Cuamba Roads ───
MkPage -f "project-cuamba-road.html" -pn "4" `
  -pt "ESIA Cuamba Roads, Niassa Province" `
  -md "ESIA for Cuamba-Insaca and Cuamba-Metarica road reconstruction in Niassa Province, World Bank financed — Enviestudos." `
  -hlEN "Roads &amp; Bridges &bull; Niassa Province" -hlPT "Estradas e Pontes &bull; Prov&iacute;ncia do Niassa" `
  -bc "Cuamba Roads ESIA" -yr "2020&ndash;2021" -prov "Niassa" `
  -cl "Think Tank Consultants, SA" -fund "World Bank" -sec "Roads &amp; Bridges" `
  -svd "ESIA &bull; Scoping Report &bull; ToR &bull; ESMP &bull; Public Consultations" `
  -tgs '<span class="project-tag">World Bank</span><span class="project-tag">ESIA</span><span class="project-tag">ESMP</span><span class="project-tag">Road Rehabilitation</span><span class="project-tag">Niassa</span>' `
  -oEN "<p>Enviestudos undertook the full ESIA for the reconstruction of two road segments in Niassa Province &mdash; Cuamba to Insaca and Cuamba to Metarica &mdash; financed by the World Bank. The study covered the complete regulatory process from environmental categorisation through to submission of the approved ESIA report, prepared on behalf of Think Tank Consultants, SA.</p><p>These remote corridors in northern Mozambique cross ecologically sensitive areas and pass through rural communities highly dependent on the land for their livelihoods, requiring careful impact assessment and meaningful community engagement throughout the study.</p>" `
  -oPT "<p>A Enviestudos realizou o EIA completo para a reconstru&ccedil;&atilde;o de dois segmentos de estrada na Prov&iacute;ncia do Niassa &mdash; de Cuamba a Insaca e de Cuamba a Metarica &mdash; financiados pelo Banco Mundial. O estudo abrangeu o processo regulat&oacute;rio completo, desde a categoriza&ccedil;&atilde;o ambiental at&eacute; &agrave; submiss&atilde;o do Relat&oacute;rio de EIA aprovado, preparado em nome da Think Tank Consultants, SA.</p><p>Estes corredores remotos no norte de Mo&ccedil;ambique atravessam &aacute;reas ecologicamente sens&iacute;veis e comunidades rurais altamente dependentes da terra, exigindo uma cuidadosa avalia&ccedil;&atilde;o de impacto e envolvimento comunit&aacute;rio efectivo ao longo do estudo.</p>" `
  -scEN "<li>Environmental categorisation and Instruction Process submission to ANAMA</li><li>Pre-feasibility Environmental Scoping Report</li><li>Terms of Reference (ToR) preparation and regulatory submission</li><li>Baseline environmental and socioeconomic surveys</li><li>Public consultation meetings in affected communities</li><li>Impact identification, prediction, and significance evaluation</li><li>Final ESIA Report including ESMP preparation</li>" `
  -scPT "<li>Categoriza&ccedil;&atilde;o ambiental e submiss&atilde;o do Processo de Instru&ccedil;&atilde;o ao ANAMA</li><li>Relat&oacute;rio de Delimita&ccedil;&atilde;o de Pr&eacute;-viabilidade Ambiental</li><li>Elabora&ccedil;&atilde;o dos Termos de Refer&ecirc;ncia (ToR) e submiss&atilde;o regulat&oacute;ria</li><li>Levantamentos de base ambiental e socioecon&oacute;mica</li><li>Reuni&otilde;es de consulta p&uacute;blica nas comunidades afectadas</li><li>Identifica&ccedil;&atilde;o, previs&atilde;o e avalia&ccedil;&atilde;o da signific&acirc;ncia dos impactos</li><li>Elabora&ccedil;&atilde;o do Relat&oacute;rio Final de EIA incluindo PGAS</li>" `
  -evEN "<li><strong>Corridor ecology:</strong> Miombo woodland, wetlands, and riparian habitats along both road alignments requiring baseline characterisation.</li><li><strong>Resettlement &amp; livelihoods:</strong> Impacts on roadside communities and smallholder farmers, including livelihood restoration provisions in the ESMP.</li><li><strong>Drainage &amp; erosion:</strong> Construction-phase soil erosion and drainage management on unpaved rural sections.</li><li><strong>Workforce influx:</strong> HIV/AIDS and GBV risks associated with construction workforce in remote communities.</li>" `
  -evPT "<li><strong>Ecologia do corredor:</strong> Mata miombo, zonas h&uacute;midas e habitats rip&aacute;rios ao longo dos dois tra&ccedil;ados de estrada que requerem caracteriza&ccedil;&atilde;o de base.</li><li><strong>Reassentamento e meios de subsist&ecirc;ncia:</strong> Impactos nas comunidades marginais e agricultores familiares, incluindo disposi&ccedil;&otilde;es de restaura&ccedil;&atilde;o de meios de subsist&ecirc;ncia no PGAS.</li><li><strong>Drenagem e eros&atilde;o:</strong> Eros&atilde;o do solo na fase de constru&ccedil;&atilde;o e gest&atilde;o da drenagem em sec&ccedil;&otilde;es rurais n&atilde;o pavimentadas.</li><li><strong>Afluxo de m&atilde;o-de-obra:</strong> Riscos de VIH/SIDA e VBG associados &agrave; for&ccedil;a de trabalho de constru&ccedil;&atilde;o em comunidades remotas.</li>" `
  -rEN "The ESIA provided the World Bank and the Government of Mozambique with fully compliant environmental documentation, enabling the road reconstruction project to advance to construction with approved mitigation measures and monitoring frameworks in place." `
  -rPT "O EIA forneceu ao Banco Mundial e ao Governo de Mo&ccedil;ambique documenta&ccedil;&atilde;o ambiental totalmente conforme, permitindo que o projecto de reconstru&ccedil;&atilde;o rodovi&aacute;ria avan&ccedil;asse para a constru&ccedil;&atilde;o com medidas de mitiga&ccedil;&atilde;o aprovadas e quadros de monitoriza&ccedil;&atilde;o em vigor." `
  -svl "$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')" `
  -rel "$(MkRc 'project-lurio.html' 'Roads &amp; Bridges &bull; 2021&ndash;2022' 'ESIA &mdash; Bridge over L&uacute;rio River' 'Full ESIA for cross-province bridge connecting Niassa and Nampula provinces, financed by Chinese Bank.')$(MkRc 'project-milange-esia.html' 'Roads &amp; Bridges &bull; 2007&ndash;2008' 'ESIA &mdash; Milange&ndash;Mocuba Road Upgrading' 'Comprehensive ESIA for EU-financed road upgrading in Zambezia Province, prepared for BCEOM.')"

# ─── Project 5: Milange Decommissioning ───
MkPage -f "project-milange-decommission.html" -pn "5" `
  -pt "Milange-Mocuba Corridor Phase II Decommissioning" `
  -md "Environmental decommissioning inspection for Milange-Mocuba Corridor Phase II, Zambezia Province, EU-funded — Enviestudos." `
  -hlEN "Roads &amp; Bridges &bull; Zambezia Province" -hlPT "Estradas e Pontes &bull; Prov&iacute;ncia da Zamb&eacute;zia" `
  -bc "Milange-Mocuba Decommissioning" -yr "2019" -prov "Zambezia" `
  -cl "EU-financed Project" -fund "European Union" -sec "Roads &amp; Bridges" `
  -svd "Environmental Supervision &bull; Decommissioning Inspection &bull; Site Closure Report" `
  -tgs '<span class="project-tag">EU</span><span class="project-tag">Supervision</span><span class="project-tag">Decommissioning</span><span class="project-tag">Site Closure</span><span class="project-tag">Zambezia</span>' `
  -oEN "<p>Following completion of construction works on the Milange-Mocuba Corridor Phase II road project in Zambezia Province, Enviestudos conducted the environmental decommissioning inspection of all project sites. This involved verifying that all construction infrastructure had been correctly rehabilitated and closed in compliance with the approved ESMP.</p><p>The inspection covered the full extent of the road corridor including construction camps, borrow pits, quarries, and access routes, assessing the final environmental status of each site against defined closure requirements.</p>" `
  -oPT "<p>Ap&oacute;s a conclus&atilde;o das obras de constru&ccedil;&atilde;o do Corredor Milange-Mocuba Fase II na Prov&iacute;ncia da Zamb&eacute;zia, a Enviestudos realizou a inspec&ccedil;&atilde;o de desmantelamento ambiental de todos os locais do projecto. O trabalho envolveu a verifica&ccedil;&atilde;o de que toda a infraestrutura de constru&ccedil;&atilde;o havia sido correctamente reabilitada e encerrada em conformidade com o PGAS aprovado.</p><p>A inspec&ccedil;&atilde;o abrangeu toda a extens&atilde;o do corredor rodovi&aacute;rio, incluindo acampamentos, zonas de empr&eacute;stimo, pedreiras e vias de acesso, avaliando o estado ambiental final de cada local.</p>" `
  -scEN "<li>Inspection of all construction campsites for environmental compliance and rehabilitation</li><li>Assessment of quarry sites for safe closure and slope stabilisation</li><li>Inspection of borrow pit sites for land rehabilitation and drainage restoration</li><li>Review of access road conditions and vegetation recovery progress</li><li>Verification of waste disposal areas and hazardous materials management</li><li>Preparation of decommissioning inspection sheets for all sites</li><li>Final decommissioning compliance report</li>" `
  -scPT "<li>Inspec&ccedil;&atilde;o de todos os acampamentos de constru&ccedil;&atilde;o para conformidade ambiental e reabilita&ccedil;&atilde;o</li><li>Avalia&ccedil;&atilde;o dos locais de pedreira para encerramento seguro e estabiliza&ccedil;&atilde;o de taludes</li><li>Inspec&ccedil;&atilde;o das zonas de empr&eacute;stimo para reabilita&ccedil;&atilde;o do solo e restaura&ccedil;&atilde;o da drenagem</li><li>Revis&atilde;o das condi&ccedil;&otilde;es das vias de acesso e progresso da recupera&ccedil;&atilde;o vegetal</li><li>Verifica&ccedil;&atilde;o das &aacute;reas de dep&oacute;sito de res&iacute;duos e gest&atilde;o de materiais perigosos</li><li>Elabora&ccedil;&atilde;o de fichas de inspec&ccedil;&atilde;o de desmantelamento para todos os locais</li><li>Relat&oacute;rio final de conformidade do desmantelamento</li>" `
  -evEN "<li><strong>Land rehabilitation:</strong> Topsoil restoration and vegetation re-establishment at all disturbed borrow pit sites.</li><li><strong>Slope stability:</strong> Erosion prevention and stabilisation measures at quarry sites post-extraction.</li><li><strong>Drainage restoration:</strong> Rehabilitation of drainage channels and restoration of natural water flow.</li><li><strong>Revegetation monitoring:</strong> Assessment of natural and assisted vegetation recovery at closed sites.</li>" `
  -evPT "<li><strong>Reabilita&ccedil;&atilde;o do solo:</strong> Restaura&ccedil;&atilde;o da camada superf&iacute;cial e restabelecimento de vegeta&ccedil;&atilde;o nas zonas de empr&eacute;stimo perturbadas.</li><li><strong>Estabilidade de taludes:</strong> Medidas de preven&ccedil;&atilde;o da eros&atilde;o e estabiliza&ccedil;&atilde;o nas pedreiras ap&oacute;s extra&ccedil;&atilde;o.</li><li><strong>Restaura&ccedil;&atilde;o da drenagem:</strong> Reabilita&ccedil;&atilde;o dos canais de drenagem e restaura&ccedil;&atilde;o do fluxo natural de &aacute;gua.</li><li><strong>Monitoriza&ccedil;&atilde;o da revegeta&ccedil;&atilde;o:</strong> Avalia&ccedil;&atilde;o da recupera&ccedil;&atilde;o natural e assistida da vegeta&ccedil;&atilde;o nos locais encerrados.</li>" `
  -rEN "The decommissioning inspection confirmed satisfactory environmental closure of all Milange-Mocuba Corridor Phase II construction sites, providing certified evidence of ESMP compliance and proper site rehabilitation for the EU funder and project developer." `
  -rPT "A inspec&ccedil;&atilde;o de desmantelamento confirmou o encerramento ambiental satisfat&oacute;rio de todos os locais de constru&ccedil;&atilde;o da Fase II do Corredor Milange-Mocuba, fornecendo evid&ecirc;ncia certificada da conformidade com o PGAS e da reabilita&ccedil;&atilde;o adequada para a UE e o promotor do projecto." `
  -svl "$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')" `
  -rel "$(MkRc 'project-milange-esia.html' 'Roads &amp; Bridges &bull; 2007&ndash;2008' 'ESIA &mdash; Milange&ndash;Mocuba Road Upgrading' 'Comprehensive ESIA for EU-financed Milange-Mocuba Road upgrading project, prepared for BCEOM.')$(MkRc 'project-milange-lot2.html' 'Roads &amp; Bridges &bull; 2015' 'EHS Supervision &mdash; Milange-Mocuba Phase II, Lot 2' 'Continuous EHS supervision of construction works on EU-financed road corridor project in Zambezia.')"

# ─── Project 6: N380 Bridges ───
MkPage -f "project-n380-bridges.html" -pn "6" `
  -pt "Environmental Studies, 8 Bridges N380, Cabo Delgado" `
  -md "Environmental Simplified Studies for 8 bridges on the N380 road, Cabo Delgado Province — JICA-financed, Enviestudos." `
  -hlEN "Roads &amp; Bridges &bull; Cabo Delgado Province" -hlPT "Estradas e Pontes &bull; Prov&iacute;ncia de Cabo Delgado" `
  -bc "N380 Bridges ESS, Cabo Delgado" -yr "2018&ndash;2019" -prov "Cabo Delgado" `
  -cl "JICA (Japan International Cooperation Agency)" -fund "JICA" -sec "Roads &amp; Bridges" `
  -svd "ESS &bull; ToR &bull; EMP &bull; Public Consultations" `
  -tgs '<span class="project-tag">JICA</span><span class="project-tag">ESS</span><span class="project-tag">Bridges</span><span class="project-tag">Cabo Delgado</span><span class="project-tag">EMP</span>' `
  -oEN "<p>Enviestudos prepared Environmental Simplified Studies (ESS) for eight bridge construction projects on the N380 road in Cabo Delgado Province, financed by JICA. The bridges are located across four districts: Muidumbe, Mocimba da Praia, Macomia, and Ancuabe.</p><p>The ESS type, applicable to Category B projects under Mozambican environmental law, required streamlined but rigorous environmental assessment with site-specific impact evaluation and Environmental Management Plans for each bridge location.</p>" `
  -oPT "<p>A Enviestudos elaborou Estudos Ambientais Simplificados (EAS) para oito projectos de constru&ccedil;&atilde;o de pontes na estrada N380 na Prov&iacute;ncia de Cabo Delgado, financiados pela JICA. As pontes est&atilde;o distribu&iacute;das por quatro distritos: Muidumbe, Mocimba da Praia, Macomia e Ancuabe.</p><p>O tipo EAS, aplic&aacute;vel a projectos de Categoria B ao abrigo da legisla&ccedil;&atilde;o ambiental mo&ccedil;ambicana, exigiu uma avalia&ccedil;&atilde;o ambiental simplificada mas rigorosa com avalia&ccedil;&atilde;o de impacto espec&iacute;fica e Planos de Gest&atilde;o Ambiental para cada local de ponte.</p>" `
  -scEN "<li>Terms of Reference (ToR) preparation for all eight bridge sites across four districts</li><li>Site visits and environmental baseline surveys at each river crossing location</li><li>Public consultation meetings in communities across four districts</li><li>Site-specific impact assessment for bridge construction and operational phases</li><li>Environmental Management Plans (EMP) for each individual bridge location</li><li>Final consolidated ESS Report covering all eight assessments</li>" `
  -scPT "<li>Elabora&ccedil;&atilde;o dos Termos de Refer&ecirc;ncia (ToR) para todos os oito locais de pontes em quatro distritos</li><li>Visitas de campo e levantamentos de base ambiental em cada travessia fluvial</li><li>Reuni&otilde;es de consulta p&uacute;blica nas comunidades em quatro distritos</li><li>Avalia&ccedil;&atilde;o de impacto espec&iacute;fica por local para as fases de constru&ccedil;&atilde;o e opera&ccedil;&atilde;o das pontes</li><li>Planos de Gest&atilde;o Ambiental (PGA) para cada local de ponte individual</li><li>Relat&oacute;rio Final de EAS consolidado abrangendo as oito avalia&ccedil;&otilde;es</li>" `
  -evEN "<li><strong>Aquatic ecology:</strong> River channel ecology and biodiversity at each of the eight crossings, including fish communities and benthic habitats.</li><li><strong>Riparian habitats:</strong> Wetland and riparian vegetation at all bridge sites requiring protection during construction works.</li><li><strong>Fishing activities:</strong> Impacts on local fishing livelihoods and community water use during bridge construction phases.</li><li><strong>Sedimentation:</strong> Erosion and suspended sediment loading in watercourses during construction activities.</li>" `
  -evPT "<li><strong>Ecologia aqu&aacute;tica:</strong> Ecologia dos cursos de &aacute;gua e biodiversidade em cada uma das oito travessias, incluindo comunidades de peixes e habitats bent&oacute;nicos.</li><li><strong>Habitats rip&aacute;rios:</strong> Vegeta&ccedil;&atilde;o h&uacute;mida e rip&aacute;ria em todos os locais de pontes que requerem prote&ccedil;&atilde;o durante as obras.</li><li><strong>Actividades de pesca:</strong> Impactos nos meios de subsist&ecirc;ncia piscatores locais e uso comunit&aacute;rio de &aacute;gua durante a constru&ccedil;&atilde;o das pontes.</li><li><strong>Sedimenta&ccedil;&atilde;o:</strong> Eros&atilde;o e carga de sedimentos em suspens&atilde;o nos cursos de &aacute;gua durante as actividades de constru&ccedil;&atilde;o.</li>" `
  -rEN "The eight ESS studies provided JICA and the Government of Mozambique with the required environmental documentation for all bridges across four districts of Cabo Delgado Province, enabling construction to proceed in compliance with Mozambican environmental law and JICA&rsquo;s environmental and social guidelines." `
  -rPT "Os oito estudos EAS forneceram &agrave; JICA e ao Governo de Mo&ccedil;ambique a documenta&ccedil;&atilde;o ambiental necess&aacute;ria para todas as pontes em quatro distritos da Prov&iacute;ncia de Cabo Delgado, permitindo que a constru&ccedil;&atilde;o prosseguisse em conformidade com a legisla&ccedil;&atilde;o ambiental mo&ccedil;ambicana e as directrizes da JICA." `
  -svl "$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')" `
  -rel "$(MkRc 'project-incomati-bridge.html' 'Infrastructure &bull; 2015' 'ESIA &mdash; Bridge over Incomati River, Magude' 'Full ESIA for World Bank-financed bridge over the Incomati River in Maputo Province.')$(MkRc 'project-lurio.html' 'Roads &amp; Bridges &bull; 2021&ndash;2022' 'ESIA &mdash; Bridge over L&uacute;rio River' 'Full ESIA for bridge connecting Niassa and Nampula provinces, financed by Chinese Bank.')"

# ─── Project 7: Nacala Water Supply ───
MkPage -f "project-nacala-water.html" -pn "7" `
  -pt "Environmental Supervision, Nacala Porto Water Supply Network" `
  -md "Environmental supervision for Nacala Porto water supply network rehabilitation, Nampula Province, IDA-financed — Enviestudos." `
  -hlEN "Water &amp; Sanitation &bull; Nampula Province" -hlPT "&Aacute;gua e Saneamento &bull; Prov&iacute;ncia de Nampula" `
  -bc "Nacala Porto Water Supply Supervision" -yr "2016&ndash;2018" -prov "Nampula" `
  -cl "IDA / World Bank Water Project" -fund "IDA (World Bank Group)" -sec "Water &amp; Sanitation" `
  -svd "Environmental Supervision &bull; Site Monitoring &bull; Periodic Reports" `
  -tgs '<span class="project-tag">IDA</span><span class="project-tag">Supervision</span><span class="project-tag">Water Supply</span><span class="project-tag">Nampula</span><span class="project-tag">World Bank</span>' `
  -oEN "<p>Enviestudos provided environmental supervision services for the rehabilitation and expansion of the water supply network in Nacala Porto, Nampula Province, financed by IDA (International Development Association — World Bank Group). The assignment involved monitoring environmental performance throughout the construction period.</p><p>Nacala Porto is one of Mozambique&rsquo;s key port cities and the water supply upgrade was critical for improving safe water access for the city&rsquo;s growing population.</p>" `
  -oPT "<p>A Enviestudos prestou servi&ccedil;os de supervis&atilde;o ambiental para a reabilita&ccedil;&atilde;o e expans&atilde;o da rede de abastecimento de &aacute;gua de Nacala Porto, Prov&iacute;ncia de Nampula, financiados pela IDA (Associa&ccedil;&atilde;o Internacional de Desenvolvimento &mdash; Grupo Banco Mundial). A miss&atilde;o envolveu a monitoriza&ccedil;&atilde;o do desempenho ambiental durante todo o per&iacute;odo de constru&ccedil;&atilde;o.</p><p>Nacala Porto &eacute; uma das principais cidades portu&aacute;rias de Mo&ccedil;ambique e a actualiza&ccedil;&atilde;o do abastecimento de &aacute;gua foi fundamental para melhorar o acesso &agrave; &aacute;gua pot&aacute;vel para a crescente popula&ccedil;&atilde;o da cidade.</p>" `
  -scEN "<li>Review of environmental and social reports and management plans</li><li>Regular site surveys and environmental performance monitoring</li><li>Verification of environmental management implementation by contractors</li><li>Monitoring of construction-phase impacts on the urban environment</li><li>Community consultation follow-up and grievance tracking</li><li>Preparation of periodic environmental monitoring reports</li>" `
  -scPT "<li>Revis&atilde;o de relat&oacute;rios ambientais e sociais e planos de gest&atilde;o</li><li>Levantamentos regulares de campo e monitoriza&ccedil;&atilde;o do desempenho ambiental</li><li>Verifica&ccedil;&atilde;o da implementa&ccedil;&atilde;o da gest&atilde;o ambiental pelos empreiteiros</li><li>Monitoriza&ccedil;&atilde;o dos impactos das obras na fase de constru&ccedil;&atilde;o no ambiente urbano</li><li>Seguimento de consultas comunit&aacute;rias e registo de queixas</li><li>Elabora&ccedil;&atilde;o de relat&oacute;rios peri&oacute;dicos de monitoriza&ccedil;&atilde;o ambiental</li>" `
  -evEN "<li><strong>Urban construction impacts:</strong> Dust, noise, and traffic disruption in residential and commercial areas of Nacala Porto during pipe-laying works.</li><li><strong>Drainage systems:</strong> Trenching and excavation impacts on existing urban drainage infrastructure requiring protection.</li><li><strong>Water quality:</strong> Protection of existing water sources and distribution systems during construction activities.</li><li><strong>Waste management:</strong> Excavation spoil disposal and construction waste management in the urban context.</li>" `
  -evPT "<li><strong>Impactos da constru&ccedil;&atilde;o urbana:</strong> Poeira, ru&iacute;do e perturba&ccedil;&atilde;o do tr&aacute;fego em &aacute;reas residenciais e comerciais de Nacala Porto durante os trabalhos de assentamento de tubagens.</li><li><strong>Sistemas de drenagem:</strong> Impactos de escava&ccedil;&atilde;o e abertura de trincheiras na infraestrutura de drenagem urbana existente.</li><li><strong>Qualidade da &aacute;gua:</strong> Prote&ccedil;&atilde;o de fontes de &aacute;gua existentes e sistemas de distribui&ccedil;&atilde;o durante as actividades de constru&ccedil;&atilde;o.</li><li><strong>Gest&atilde;o de res&iacute;duos:</strong> Deposi&ccedil;&atilde;o de solos escavados e gest&atilde;o de res&iacute;duos de constru&ccedil;&atilde;o no contexto urbano.</li>" `
  -rEN "Environmental supervision ensured the Nacala Porto water supply rehabilitation was completed with minimal environmental and social impacts, in full compliance with IDA requirements and Mozambican environmental law, contributing to improved water access for the city&rsquo;s population." `
  -rPT "A supervis&atilde;o ambiental garantiu que a reabilita&ccedil;&atilde;o do abastecimento de &aacute;gua de Nacala Porto foi conclu&iacute;da com impactos ambientais e sociais m&iacute;nimos, em plena conformidade com os requisitos da IDA e a legisla&ccedil;&atilde;o ambiental mo&ccedil;ambicana, contribuindo para a melhoria do acesso &agrave; &aacute;gua para a popula&ccedil;&atilde;o da cidade." `
  -svl "$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')" `
  -rel "$(MkRc 'project-sanitation-cities.html' 'Water &amp; Sanitation &bull; 2010&ndash;2011' 'ESIA &mdash; Sanitation Improvements, Pemba, Nampula &amp; Quelimane' 'Multi-city ESIA for MCC-financed sanitation improvements in three Mozambican cities.')$(MkRc 'project-aias-water.html' 'Water &amp; Sanitation &bull; 2011' 'Technical Assistance to AIAS &mdash; Water Supply &amp; Sanitation' 'ESIA preparation and capacity building for AIAS water supply projects, World Bank financed.')"

# ─── Project 8: N103 R657 Roads ───
MkPage -f "project-n103-roads.html" -pn "8" `
  -pt "EHS Supervision, Roads N103 and R657, Zambezia / Niassa" `
  -md "EHS supervision for rehabilitation of Roads N103 and R657, Magige–Etatara–Cuamba, World Bank financed — Enviestudos." `
  -hlEN "Roads &amp; Bridges &bull; Zambezia / Niassa Provinces" -hlPT "Estradas e Pontes &bull; Zamb&eacute;zia / Niassa" `
  -bc "N103 &amp; R657 Roads EHS Supervision" -yr "2014&ndash;2016" -prov "Zambezia / Niassa" `
  -cl "Consulmar Mozambique (Supervision Team)" -fund "World Bank" -sec "Roads &amp; Bridges" `
  -svd "EHS Supervision &bull; ESIA Monitoring &bull; Periodic Reports" `
  -tgs '<span class="project-tag">World Bank</span><span class="project-tag">EHS Supervision</span><span class="project-tag">Roads</span><span class="project-tag">Zambezia</span><span class="project-tag">Niassa</span>' `
  -oEN "<p>Enviestudos provided Environmental Health and Safety (EHS) supervision services as part of the civil works supervision team for the rehabilitation of Roads N103 and R657 (Magige&ndash;Etatara&ndash;Cuamba) spanning Zambezia and Niassa provinces, financed by the World Bank and contracted through Consulmar Mozambique.</p><p>The role involved continuous monitoring of the contractor&rsquo;s compliance with the approved ESIA and Environmental Management Plan (EMP) throughout the multi-year construction works.</p>" `
  -oPT "<p>A Enviestudos prestou servi&ccedil;os de supervis&atilde;o de Sa&uacute;de, Seguran&ccedil;a e Ambiente (HSA) como parte da equipa de supervis&atilde;o de obras civis para a reabilita&ccedil;&atilde;o das Estradas N103 e R657 (Magige&ndash;Etatara&ndash;Cuamba) nas Prov&iacute;ncias de Zamb&eacute;zia e Niassa, financiadas pelo Banco Mundial, contratada atrav&eacute;s da Consulmar Mo&ccedil;ambique.</p><p>A fun&ccedil;&atilde;o envolveu a monitoriza&ccedil;&atilde;o cont&iacute;nua da conformidade do empreiteiro com o EIA e o Plano de Gest&atilde;o Ambiental (PGA) aprovados durante as obras de constru&ccedil;&atilde;o plurianuais.</p>" `
  -scEN "<li>Regular site inspections along the N103 and R657 road corridor across two provinces</li><li>Monitoring of EHS mitigation measures per the approved ESIA and EMP</li><li>Non-conformance tracking and corrective action follow-up</li><li>Environmental inspection of borrow pits, quarries, and construction camps</li><li>Health and safety performance monitoring of contractor workforce</li><li>Community liaison and grievance monitoring along the road corridor</li><li>Preparation of periodic EHS monitoring reports for the World Bank</li>" `
  -scPT "<li>Inspec&ccedil;&otilde;es regulares de campo ao longo do corredor N103 e R657 em duas prov&iacute;ncias</li><li>Monitoriza&ccedil;&atilde;o das medidas de mitiga&ccedil;&atilde;o de HSA conforme o EIA e PGA aprovados</li><li>Registo de n&atilde;o-conformidades e seguimento de ac&ccedil;&otilde;es correctivas</li><li>Inspec&ccedil;&atilde;o ambiental de zonas de empr&eacute;stimo, pedreiras e acampamentos de constru&ccedil;&atilde;o</li><li>Monitoriza&ccedil;&atilde;o do desempenho de sa&uacute;de e seguran&ccedil;a da for&ccedil;a de trabalho</li><li>Liga&ccedil;&atilde;o comunit&aacute;ria e monitoriza&ccedil;&atilde;o de queixas ao longo do corredor rodovi&aacute;rio</li><li>Elabora&ccedil;&atilde;o de relat&oacute;rios peri&oacute;dicos de monitoriza&ccedil;&atilde;o de HSA para o Banco Mundial</li>" `
  -evEN "<li><strong>Multi-province corridor compliance:</strong> EHS monitoring across a remote road corridor spanning two provinces with varied ecological conditions.</li><li><strong>Borrow pit rehabilitation:</strong> Ongoing monitoring of extraction site management and progressive rehabilitation.</li><li><strong>River crossings:</strong> Environmental protection of watercourses during bridge construction and culvert installation.</li><li><strong>HIV/AIDS prevention:</strong> Monitoring of workforce health programs in areas with high community interaction risk.</li>" `
  -evPT "<li><strong>Conformidade no corredor multi-provincial:</strong> Monitoriza&ccedil;&atilde;o de HSA ao longo de um corredor rodovi&aacute;rio remoto abrangendo duas prov&iacute;ncias com condi&ccedil;&otilde;es ecol&oacute;gicas variadas.</li><li><strong>Reabilita&ccedil;&atilde;o de zonas de empr&eacute;stimo:</strong> Monitoriza&ccedil;&atilde;o cont&iacute;nua da gest&atilde;o dos locais de extra&ccedil;&atilde;o e reabilita&ccedil;&atilde;o progressiva.</li><li><strong>Travessias fluviais:</strong> Prote&ccedil;&atilde;o ambiental dos cursos de &aacute;gua durante a constru&ccedil;&atilde;o de pontes e instala&ccedil;&atilde;o de aquedutos.</li><li><strong>Preven&ccedil;&atilde;o do VIH/SIDA:</strong> Monitoriza&ccedil;&atilde;o dos programas de sa&uacute;de da for&ccedil;a de trabalho em &aacute;reas com elevado risco de intera&ccedil;&atilde;o comunit&aacute;ria.</li>" `
  -rEN "Continuous EHS supervision contributed to maintaining World Bank environmental and social compliance throughout the N103 and R657 rehabilitation works, ensuring that approved mitigation measures were effectively implemented and documented across both provinces." `
  -rPT "A supervis&atilde;o cont&iacute;nua de HSA contribuiu para a manuten&ccedil;&atilde;o da conformidade ambiental e social do Banco Mundial nas obras de reabilita&ccedil;&atilde;o das N103 e R657, garantindo que as medidas de mitiga&ccedil;&atilde;o aprovadas foram efectivamente implementadas e documentadas nas duas prov&iacute;ncias." `
  -svl "$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')" `
  -rel "$(MkRc 'project-n14-supervision.html' 'Roads &amp; Bridges &bull; Oct&ndash;Nov 2011' 'Supervision &mdash; N14 Road, Marrupa&ndash;Rua&ccedil;a (Lot B)' 'Health and Safety supervision for civil works on N14 Road in Niassa Province, World Bank financed.')$(MkRc 'project-en1-namacurra.html' 'Roads &amp; Bridges &bull; 2005&ndash;2008' 'ESIA Supervision &mdash; EN1, Namacurra&ndash;Rio Ligonha' 'Three-year ESIA supervision for EU-financed EN1 road rehabilitation in Zambezia Province.')"

# ─── Project 9: N1 Rio Save ───
MkPage -f "project-n1-save.html" -pn "9" `
  -pt "ESS Road N1 Rehabilitation, Rio Save–Muxungue, Sofala" `
  -md "Environmental Simplified Study for Road N1 rehabilitation, Rio Save to Muxungue, Sofala Province, EU-financed — Enviestudos." `
  -hlEN "Roads &amp; Bridges &bull; Sofala Province" -hlPT "Estradas e Pontes &bull; Prov&iacute;ncia de Sofala" `
  -bc "Road N1 Rio Save ESS" -yr "2015&ndash;2016" -prov "Sofala" `
  -cl "SAI Consulting Engineers, India" -fund "European Union" -sec "Roads &amp; Bridges" `
  -svd "ESS &bull; ToR &bull; EMP &bull; Public Consultations" `
  -tgs '<span class="project-tag">EU</span><span class="project-tag">ESS</span><span class="project-tag">Road N1</span><span class="project-tag">Sofala</span><span class="project-tag">EMP</span>' `
  -oEN "<p>Enviestudos prepared an Environmental Simplified Study (ESS) for the rehabilitation of Road N1 between Rio Save and Muxungue in Sofala Province, financed by the European Union. The study was prepared in support of SAI Consulting Engineers (India), who led the feasibility and engineering design work.</p><p>The N1 is Mozambique&rsquo;s primary north-south trunk road, and this section connects the south with the central regions, passing through ecologically and socially sensitive areas of Sofala Province.</p>" `
  -oPT "<p>A Enviestudos elaborou um Estudo Ambiental Simplificado (EAS) para a reabilita&ccedil;&atilde;o da Estrada N1 entre o Rio Save e Muxungue na Prov&iacute;ncia de Sofala, financiado pela Uni&atilde;o Europeia. O estudo foi preparado em apoio &agrave; SAI Consulting Engineers (&Iacute;ndia), que liderou os estudos de viabilidade e projecto de engenharia.</p><p>A N1 &eacute; a principal estrada nacional de Mo&ccedil;ambique no sentido norte-sul, e esta sec&ccedil;&atilde;o liga o sul &agrave;s regi&otilde;es centrais, atravessando &aacute;reas ecologicamente e socialmente sens&iacute;veis da Prov&iacute;ncia de Sofala.</p>" `
  -scEN "<li>Terms of Reference (ToR) preparation for the ESS study</li><li>Environmental baseline assessment along the road corridor in Sofala Province</li><li>Public consultation meetings with roadside communities</li><li>Impact assessment for road rehabilitation and construction phases</li><li>Environmental Management Plan (EMP) preparation</li><li>Final ESS Report submission to Mozambican environmental authorities</li>" `
  -scPT "<li>Elabora&ccedil;&atilde;o dos Termos de Refer&ecirc;ncia (ToR) para o estudo EAS</li><li>Avalia&ccedil;&atilde;o de base ambiental ao longo do corredor rodovi&aacute;rio na Prov&iacute;ncia de Sofala</li><li>Reuni&otilde;es de consulta p&uacute;blica com as comunidades marginais</li><li>Avalia&ccedil;&atilde;o de impacto para as fases de reabilita&ccedil;&atilde;o e constru&ccedil;&atilde;o da estrada</li><li>Elabora&ccedil;&atilde;o do Plano de Gest&atilde;o Ambiental (PGA)</li><li>Submiss&atilde;o do Relat&oacute;rio Final de EAS &agrave;s autoridades ambientais mo&ccedil;ambicanas</li>" `
  -evEN "<li><strong>Corridor biodiversity:</strong> Ecological baseline of the road corridor environment in Sofala Province, including vegetation types and wildlife.</li><li><strong>Rio Save crossing:</strong> Aquatic ecology and riverside habitat protection at the major river crossing.</li><li><strong>Roadside communities:</strong> Impacts of construction activities on communities along the N1 rehabilitation section.</li><li><strong>Drainage &amp; erosion:</strong> Erosion management and drainage improvement along the rehabilitated road sections.</li>" `
  -evPT "<li><strong>Biodiversidade do corredor:</strong> Base ecol&oacute;gica do ambiente do corredor rodovi&aacute;rio na Prov&iacute;ncia de Sofala, incluindo tipos de vegeta&ccedil;&atilde;o e fauna.</li><li><strong>Travessia do Rio Save:</strong> Ecologia aqu&aacute;tica e prote&ccedil;&atilde;o do habitat ribeirinho na travessia fluvial principal.</li><li><strong>Comunidades marginais:</strong> Impactos das actividades de constru&ccedil;&atilde;o nas comunidades ao longo da sec&ccedil;&atilde;o de reabilita&ccedil;&atilde;o da N1.</li><li><strong>Drenagem e eros&atilde;o:</strong> Gest&atilde;o da eros&atilde;o e melhoria da drenagem ao longo das sec&ccedil;&otilde;es reabilitadas.</li>" `
  -rEN "The ESS and EMP provided the EU and the Government of Mozambique with the required environmental documentation for the N1 Rio Save-Muxungue rehabilitation, meeting both Mozambican environmental law requirements and EU safeguard standards for transport infrastructure projects." `
  -rPT "O EAS e o PGA forneceram &agrave; UE e ao Governo de Mo&ccedil;ambique a documenta&ccedil;&atilde;o ambiental necess&aacute;ria para a reabilita&ccedil;&atilde;o da N1 Rio Save-Muxungue, cumprindo os requisitos da legisla&ccedil;&atilde;o ambiental mo&ccedil;ambicana e as normas de salvaguarda da UE para projectos de infraestrutura de transportes." `
  -svl "$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')" `
  -rel "$(MkRc 'project-milange-esia.html' 'Roads &amp; Bridges &bull; 2007&ndash;2008' 'ESIA &mdash; Milange&ndash;Mocuba Road Upgrading' 'Comprehensive ESIA for EU-financed road upgrading in Zambezia Province.')$(MkRc 'project-en1-vilanculos.html' 'Roads &amp; Bridges &bull; 2002' 'ESMP &mdash; EN1, Nhachengue&ndash;Vilanculos' 'ESMP for EU-financed EN1 rehabilitation in Inhambane Province &mdash; one of Enviestudos&rsquo; founding projects.')"

# ─── Project 10: Incomati Bridge ───
MkPage -f "project-incomati-bridge.html" -pn "10" `
  -pt "ESIA Bridge over Incomati River, Magude, Maputo Province" `
  -md "ESIA for new bridge over Incomati River at Magude Village, Maputo Province, World Bank financed — Enviestudos." `
  -hlEN "Infrastructure &bull; Maputo Province" -hlPT "Infraestrutura &bull; Prov&iacute;ncia de Maputo" `
  -bc "Incomati Bridge ESIA, Magude" -yr "2015" -prov "Maputo" `
  -cl "SAI Consulting Engineers" -fund "World Bank" -sec "Infrastructure" `
  -svd "ESIA &bull; Scoping Report &bull; ToR &bull; ESMP &bull; Public Consultations" `
  -tgs '<span class="project-tag">World Bank</span><span class="project-tag">ESIA</span><span class="project-tag">Bridge</span><span class="project-tag">Incomati River</span><span class="project-tag">Maputo Province</span>' `
  -oEN "<p>Enviestudos conducted a full Environmental and Social Impact Assessment (ESIA) for a new bridge over the Incomati River at Magude Village in Maputo Province, financed by the World Bank and prepared for SAI Consulting Engineers. This bridge investment aimed to improve connectivity and access for communities on both sides of the river in southern Mozambique.</p><p>The Incomati River is an internationally significant transboundary watercourse shared by Mozambique, Swaziland, and South Africa, adding environmental complexity requiring careful assessment of cross-border hydrological impacts.</p>" `
  -oPT "<p>A Enviestudos realizou um Estudo de Impacto Ambiental e Social (EIA) completo para uma nova ponte sobre o Rio Incomati na Aldeia de Magude, Prov&iacute;ncia de Maputo, financiado pelo Banco Mundial e preparado para a SAI Consulting Engineers. Este investimento visava melhorar a conectividade e o acesso para as comunidades em ambos os lados do rio no sul de Mo&ccedil;ambique.</p><p>O Rio Incomati &eacute; um curso de &aacute;gua transfronteiri&ccedil;o de import&acirc;ncia internacional partilhado por Mo&ccedil;ambique, Suz&iacute;landia e &Aacute;frica do Sul, acrescentando complexidade ambiental que exigiu uma cuidadosa avalia&ccedil;&atilde;o dos impactos hidrol&oacute;gicos transfronteiri&ccedil;os.</p>" `
  -scEN "<li>Pre-feasibility Environmental Scoping Report</li><li>Terms of Reference (ToR) preparation and submission to ANAMA</li><li>Baseline surveys: aquatic ecology, riparian vegetation, hydrology, socioeconomics</li><li>Incomati River flood risk assessment and hydrological impact evaluation</li><li>Public consultation meetings with Magude community</li><li>Impact identification and significance evaluation</li><li>Full ESIA Report and integrated ESMP preparation</li>" `
  -scPT "<li>Relat&oacute;rio de Delimita&ccedil;&atilde;o de Pr&eacute;-viabilidade Ambiental</li><li>Elabora&ccedil;&atilde;o dos Termos de Refer&ecirc;ncia (ToR) e submiss&atilde;o ao ANAMA</li><li>Levantamentos de base: ecologia aqu&aacute;tica, vegeta&ccedil;&atilde;o rip&aacute;ria, hidrologia, socioecon&oacute;mica</li><li>Avalia&ccedil;&atilde;o do risco de cheias e impacto hidrol&oacute;gico do Rio Incomati</li><li>Reuni&otilde;es de consulta p&uacute;blica com a comunidade de Magude</li><li>Identifica&ccedil;&atilde;o e avalia&ccedil;&atilde;o da signific&acirc;ncia dos impactos</li><li>Elabora&ccedil;&atilde;o do Relat&oacute;rio Final de EIA e PGAS integrado</li>" `
  -evEN "<li><strong>Transboundary watercourse:</strong> Incomati River aquatic ecology and considerations for a watercourse shared across three countries.</li><li><strong>Riparian &amp; wetland habitats:</strong> Riverside vegetation and wetland ecosystems requiring protection during bridge construction.</li><li><strong>Hydrology &amp; flood risk:</strong> River flow assessment and flood resilience design requirements for the bridge structure.</li><li><strong>Fishing community livelihoods:</strong> Impacts on fishing activities and river access for Magude communities.</li>" `
  -evPT "<li><strong>Curso de &aacute;gua transfronteiri&ccedil;o:</strong> Ecologia aqu&aacute;tica do Rio Incomati e considera&ccedil;&otilde;es para um curso de &aacute;gua partilhado por tr&ecirc;s pa&iacute;ses.</li><li><strong>Habitats rip&aacute;rios e h&uacute;midos:</strong> Vegeta&ccedil;&atilde;o ribeirinha e ecossistemas de zonas h&uacute;midas que requerem prote&ccedil;&atilde;o durante a constru&ccedil;&atilde;o da ponte.</li><li><strong>Hidrologia e risco de cheias:</strong> Avalia&ccedil;&atilde;o do fluxo fluvial e requisitos de projecto de resili&ecirc;ncia a cheias para a estrutura da ponte.</li><li><strong>Meios de subsist&ecirc;ncia da comunidade piscatora:</strong> Impactos nas actividades de pesca e no acesso ao rio para as comunidades de Magude.</li>" `
  -rEN "The World Bank-compliant ESIA enabled the Magude bridge project to advance through the regulatory approval process, providing comprehensive documentation meeting both Mozambican licensing requirements and World Bank environmental and social safeguard standards." `
  -rPT "O EIA em conformidade com o Banco Mundial permitiu que o projecto de ponte de Magude avan&ccedil;asse no processo de aprova&ccedil;&atilde;o regulat&oacute;ria, fornecendo documenta&ccedil;&atilde;o abrangente que cumpria os requisitos de licenciamento mo&ccedil;ambicanos e as normas de salvaguarda ambiental e social do Banco Mundial." `
  -svl "$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')" `
  -rel "$(MkRc 'project-lurio.html' 'Roads &amp; Bridges &bull; 2021&ndash;2022' 'ESIA &mdash; Bridge over L&uacute;rio River' 'Full ESIA for cross-province bridge connecting Niassa and Nampula provinces, financed by Chinese Bank.')$(MkRc 'project-chongoene.html' 'Infrastructure &bull; 2022' 'ESIA &mdash; Port Infrastructure Construction, Chongoene' 'Full ESIA including scoping, public consultations, and ESMP for new port infrastructure in Gaza Province.')"

# ─── Project 11: Sanitation 3 Cities ───
MkPage -f "project-sanitation-cities.html" -pn "11" `
  -pt "ESIA Sanitation Improvements, Pemba, Nampula and Quelimane" `
  -md "ESIA for sanitation improvements in Pemba, Nampula and Quelimane, MCC Mozambique Compact financed — Enviestudos." `
  -hlEN "Water &amp; Sanitation &bull; Multiple Provinces" -hlPT "&Aacute;gua e Saneamento &bull; V&aacute;rias Prov&iacute;ncias" `
  -bc "Sanitation ESIA, Three Cities" -yr "2010&ndash;2011" -prov "Multiple Provinces" `
  -cl "Louis Berger SAS" -fund "MCC Mozambique" -sec "Water &amp; Sanitation" `
  -svd "ESIA &bull; ToR &bull; ESMP &bull; Multi-City Public Consultations" `
  -tgs '<span class="project-tag">MCC</span><span class="project-tag">ESIA</span><span class="project-tag">ESMP</span><span class="project-tag">Sanitation</span><span class="project-tag">Multi-City</span>' `
  -oEN "<p>Enviestudos prepared Environmental and Social Impact Assessments (ESIAs) for sanitation improvement projects in three of Mozambique&rsquo;s major cities &mdash; Pemba, Nampula, and Quelimane &mdash; financed by the Millennium Challenge Corporation (MCC) Mozambique Compact. The study was prepared for Louis Berger SAS.</p><p>Each city&rsquo;s sanitation improvements involved different infrastructure components, requiring site-specific environmental assessment tailored to each city&rsquo;s urban context while maintaining consistency with MCC&rsquo;s environmental guidelines.</p>" `
  -oPT "<p>A Enviestudos elaborou Estudos de Impacto Ambiental e Social (EIA) para projectos de melhoria do saneamento em tr&ecirc;s das principais cidades de Mo&ccedil;ambique &mdash; Pemba, Nampula e Quelimane &mdash; financiados pelo Millennium Challenge Corporation (MCC) Compact Mo&ccedil;ambique. O estudo foi preparado para a Louis Berger SAS.</p><p>As melhorias de saneamento em cada cidade envolveram diferentes componentes de infraestrutura, exigindo uma avalia&ccedil;&atilde;o ambiental espec&iacute;fica adaptada ao contexto urbano de cada cidade, mantendo a consist&ecirc;ncia com as directrizes ambientais do MCC.</p>" `
  -scEN "<li>Pre-feasibility Environmental Scoping Reports for each of the three cities</li><li>Terms of Reference (ToR) preparation per city</li><li>Multi-city baseline environmental and socioeconomic surveys</li><li>Public consultation meetings in Pemba, Nampula, and Quelimane</li><li>City-specific impact assessment for sanitation infrastructure components</li><li>Integrated ESMPs for each city&rsquo;s sanitation improvement works</li><li>Final ESIA Reports per city and overall consolidated report</li>" `
  -scPT "<li>Relat&oacute;rios de Delimita&ccedil;&atilde;o de Pr&eacute;-viabilidade Ambiental para cada uma das tr&ecirc;s cidades</li><li>Elabora&ccedil;&atilde;o dos Termos de Refer&ecirc;ncia (ToR) por cidade</li><li>Levantamentos de base ambiental e socioecon&oacute;mica em v&aacute;rias cidades</li><li>Reuni&otilde;es de consulta p&uacute;blica em Pemba, Nampula e Quelimane</li><li>Avalia&ccedil;&atilde;o de impacto espec&iacute;fica por cidade para os componentes de infraestrutura de saneamento</li><li>PGASs integrados para as obras de melhoria de saneamento de cada cidade</li><li>Relat&oacute;rios Finais de EIA por cidade e relat&oacute;rio consolidado global</li>" `
  -evEN "<li><strong>Urban construction impacts:</strong> Site-specific construction impacts across three distinct city environments with different urban densities and sensitivities.</li><li><strong>Groundwater &amp; water quality:</strong> Protection of groundwater resources and existing water sources during construction activities.</li><li><strong>Community health:</strong> Positive health impact assessment of improved sanitation coverage and existing disease burden.</li><li><strong>Waste management:</strong> Excavation spoil and construction waste management in complex urban settings across three cities.</li>" `
  -evPT "<li><strong>Impactos da constru&ccedil;&atilde;o urbana:</strong> Impactos de constru&ccedil;&atilde;o espec&iacute;ficos por local em tr&ecirc;s ambientes urbanos distintos com densidades e sensibilidades diferentes.</li><li><strong>Aguas subterr&acirc;neas e qualidade da &aacute;gua:</strong> Prote&ccedil;&atilde;o dos recursos h&iacute;dricos subterr&acirc;neos e das fontes de &aacute;gua existentes durante as actividades de constru&ccedil;&atilde;o.</li><li><strong>Sa&uacute;de comunit&aacute;ria:</strong> Avalia&ccedil;&atilde;o do impacto positivo na sa&uacute;de da melhoria da cobertura de saneamento e da carga de doen&ccedil;a existente.</li><li><strong>Gest&atilde;o de res&iacute;duos:</strong> Gest&atilde;o de solos escavados e res&iacute;duos de constru&ccedil;&atilde;o em contextos urbanos complexos nas tr&ecirc;s cidades.</li>" `
  -rEN "The multi-city ESIA package provided MCC with compliant environmental documentation across all three Mozambican cities, supporting the successful implementation of the Millennium Challenge Corporation Compact sanitation improvements and contributing to improved public health outcomes." `
  -rPT "O pacote de EIA multi-cidade forneceu ao MCC documenta&ccedil;&atilde;o ambiental conforme para as tr&ecirc;s cidades mo&ccedil;ambicanas, apoiando a implementa&ccedil;&atilde;o bem-sucedida das melhorias de saneamento do Compact MCC e contribuindo para a melhoria dos resultados de sa&uacute;de p&uacute;blica." `
  -svl "$(MkSl 'service-esia.html' $svgEsia 'ESIA Services')$(MkSl 'service-monitoring.html' $svgSup 'Environmental Supervision')" `
  -rel "$(MkRc 'project-nacala-water.html' 'Water &amp; Sanitation &bull; 2016&ndash;2018' 'Environmental Supervision &mdash; Nacala Porto Water Supply Network' 'Environmental supervision for IDA-financed water supply rehabilitation in Nampula Province.')$(MkRc 'project-aias-water.html' 'Water &amp; Sanitation &bull; 2011' 'Technical Assistance to AIAS &mdash; Water Supply &amp; Sanitation' 'ESIA and capacity building for AIAS water supply projects, World Bank financed.')"

Write-Host "Projects 4-11 complete."
